const payload = $input.first().json.body ?? $input.first().json;

const normalizePhone = (value = '') => String(value).replace(/\D/g, '');
const normalizeStatus = (value = '') => {
  const status = String(value || '').trim().toLowerCase();

  if (['composing', 'typing', 'digitando'].includes(status)) return 'composing';
  if (['recording', 'gravando', 'gravando_audio', 'gravando-audio'].includes(status)) return 'recording';
  if (['paused', 'pause', 'stop', 'reset', 'available'].includes(status)) return 'paused';
  return 'paused';
};

const presence = normalizeStatus(payload.status || payload.presence);
const isReset = presence === 'paused';
const rawDelay = Number(payload.delay);
const delay = Number.isFinite(rawDelay)
  ? Math.max(0, rawDelay)
  : (isReset ? 0 : 300000);
const serverUrl = String(payload.server_url || payload.base_url || 'https://chatwoot.htech-servidor.space').trim().replace(/\/$/, '');

return [{
  json: {
    instancia: String(payload.instancia || payload.instance || '').trim(),
    telefone: normalizePhone(payload.telefone || payload.number || payload.phone || ''),
    presence,
    delay,
    apikey: String(payload.apikey || payload.api_key || '').trim(),
    server_url: serverUrl,
  }
}];
